package com.cognizant.springtesting; import static org.junit.jupiter.api.Assertions.*; import java.util.List; import org.junit.jupiter.api.Test; import org.springframework.beans.factory.annotation.Autowired; import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest; @DataJpaTest public class UserRepositoryTest {@Autowired UserRepository userRepository;@Test void testFindByName(){userRepository.save(new User(1L,"Aman"));userRepository.save(new User(2L,"Aman"));userRepository.save(new User(3L,"Other"));List<User> users=userRepository.findByName("Aman");assertEquals(2,users.size());assertTrue(users.stream().allMatch(user->user.getName().equals("Aman")));}}
